begin
  create schema if not exists archive;
  foreach sig in array sigs loop
    fn_name := split_part(sig, '(', 1);
    fn_args := (regexp_match(sig, '^[^(]*\((.*)\)$'))[1];
    if exists (
         select 1 from pg_proc p join pg_namespace n on n.oid=p.pronamespace
         where n.nspname='public' and p.proname=fn_name and pg_get_function_identity_arguments(p.oid)=fn_args
       ) and not exists (
         select 1 from pg_proc ap join pg_namespace an on an.oid=ap.pronamespace
         where an.nspname='archive' and ap.proname=fn_name and pg_get_function_identity_arguments(ap.oid)=fn_args
       ) then
      execute format('alter function public.%I(%s) set schema archive', fn_name, fn_args);
      insert into archive._cleanup_manifest(object_type,object_name,reason,evidence,session)
      values ('function', sig, 'tier3b dead fn (deterministic mirror): 0 db refs + 0 repo refs',
              jsonb_build_object('phase','tier3b_function'), 'claude-faxina-2026-06-20');
      moved := moved + 1;
    end if;
  end loop;
  raise notice 'Tier3b mirror archived % functions', moved;
end $$;
NOTIFY pgrst, 'reload schema';
